import React, { useState } from 'react';
import { Form, Button, Alert, Container } from 'react-bootstrap';
import { useAuth } from '../context/AuthContext';

function Login() {
  const [email, setEmail] = useState('admin@example.com');
  const [password, setPassword] = useState('password123');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    const result = await login(email, password);
    if (!result.success) setError(result.message);
    setLoading(false);
  };

  return (
    <div style={styles.background}>
      {/* Анимированные частицы на фоне */}
      <div style={styles.particles}>
        {[...Array(20)].map((_, i) => (
          <div key={i} style={{
            ...styles.particle,
            left: `${Math.random() * 100}%`,
            animationDelay: `${Math.random() * 5}s`,
            animationDuration: `${3 + Math.random() * 4}s`,
            width: `${2 + Math.random() * 4}px`,
            height: `${2 + Math.random() * 4}px`,
          }} />
        ))}
      </div>

      <Container style={styles.container}>
        {/* Логотип */}
        <div style={styles.logoWrapper}>
          <div style={styles.logoCircle}>
            <div style={styles.logoInner}>
              <svg width="50" height="50" viewBox="0 0 50 50" fill="none">
                <path d="M10 35 L20 20 L30 20 L40 35" stroke="#8B0000" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" fill="none"/>
                <circle cx="15" cy="35" r="4" stroke="#1a1a1a" strokeWidth="2.5" fill="white"/>
                <circle cx="35" cy="35" r="4" stroke="#1a1a1a" strokeWidth="2.5" fill="white"/>
                <rect x="22" y="18" width="6" height="12" rx="2" stroke="#333" strokeWidth="2" fill="rgba(139,0,0,0.1)"/>
                <line x1="25" y1="10" x2="25" y2="18" stroke="#8B0000" strokeWidth="2"/>
                <line x1="20" y1="14" x2="30" y2="14" stroke="#8B0000" strokeWidth="2"/>
              </svg>
            </div>
          </div>
        </div>

        <h1 style={styles.title}>AUTOPARTS</h1>
        <p style={styles.subtitle}>Система управления продажами автозапчастей</p>

        {/* Стеклянная карточка */}
        <div style={styles.glassCard}>
          <div style={styles.cardHeader}>
            <span style={styles.headerIcon}>🔐</span>
            <span>Вход в систему</span>
          </div>

          <div style={styles.cardBody}>
            {error && (
              <div style={styles.errorAlert}>
                <span>⚠️</span> {error}
              </div>
            )}

            <Form onSubmit={handleSubmit}>
              <div style={styles.inputGroup}>
                <label style={styles.label}>
                  <span style={styles.labelIcon}>📧</span> Email
                </label>
                <input
                  type="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  required
                  style={styles.input}
                  placeholder="Введите email"
                />
              </div>

              <div style={styles.inputGroup}>
                <label style={styles.label}>
                  <span style={styles.labelIcon}>🔒</span> Пароль
                </label>
                <input
                  type="password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  required
                  style={styles.input}
                  placeholder="Введите пароль"
                />
              </div>

              <button
                type="submit"
                disabled={loading}
                style={{
                  ...styles.button,
                  opacity: loading ? 0.7 : 1,
                  cursor: loading ? 'wait' : 'pointer',
                }}
                onMouseEnter={(e) => {
                  e.target.style.transform = 'translateY(-2px)';
                  e.target.style.boxShadow = '0 8px 25px rgba(139, 0, 0, 0.5)';
                }}
                onMouseLeave={(e) => {
                  e.target.style.transform = 'translateY(0)';
                  e.target.style.boxShadow = '0 4px 15px rgba(139, 0, 0, 0.3)';
                }}
              >
                {loading ? (
                  <span style={styles.loadingDots}>
                    <span>.</span><span>.</span><span>.</span>
                  </span>
                ) : (
                  '🚪 Войти в систему'
                )}
              </button>
            </Form>
          </div>
        </div>

        <p style={styles.footer}>
          Тестовый доступ: admin@example.com / password123
        </p>
      </Container>

      {/* CSS анимации */}
      <style>{`
        @keyframes float {
          0%, 100% { transform: translateY(0) rotate(0deg); }
          50% { transform: translateY(-20px) rotate(180deg); }
        }
        @keyframes pulse {
          0%, 100% { opacity: 0.4; }
          50% { opacity: 0.8; }
        }
        @keyframes loadingDot {
          0%, 80%, 100% { opacity: 0; }
          40% { opacity: 1; }
        }
      `}</style>
    </div>
  );
}

// Стили
const styles = {
  background: {
    minHeight: '100vh',
    background: 'linear-gradient(135deg, #0a0a0a 0%, #1a1a2e 30%, #16213e 60%, #0f3460 100%)',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    position: 'relative',
    overflow: 'hidden',
  },
  particles: {
    position: 'absolute',
    top: 0,
    left: 0,
    width: '100%',
    height: '100%',
    pointerEvents: 'none',
  },
  particle: {
    position: 'absolute',
    bottom: '-10px',
    background: 'rgba(139, 0, 0, 0.4)',
    borderRadius: '50%',
    animation: 'float 5s infinite ease-in-out',
  },
  container: {
    position: 'relative',
    zIndex: 1,
    maxWidth: 450,
    padding: '0 20px',
  },
  logoWrapper: {
    textAlign: 'center',
    marginBottom: 20,
  },
  logoCircle: {
    width: 100,
    height: 100,
    margin: '0 auto',
    borderRadius: 25,
    background: 'rgba(255, 255, 255, 0.1)',
    backdropFilter: 'blur(10px)',
    border: '2px solid rgba(255, 255, 255, 0.2)',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    boxShadow: '0 15px 35px rgba(0, 0, 0, 0.4)',
  },
  logoInner: {
    width: 70,
    height: 70,
    borderRadius: 18,
    background: 'white',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    boxShadow: '0 5px 15px rgba(0, 0, 0, 0.3)',
  },
